  const stringLength = s.length;

  // If the length is odd, it cannot be valid
  if (stringLength % 2 !== 0) {
    return false;
  }

  function generateParentheses(currentString, openCount, closeCount, maxPairs) {
    if (currentString.length === 2 * maxPairs) {
      return [currentString];
    }

    const parenthesesCombinations = [];

    if (openCount < maxPairs) {
      parenthesesCombinations.push(
        ...generateParentheses(
          currentString + '(',
          openCount + 1,
          closeCount,
          maxPairs
        )
      );
    }

    if (closeCount < openCount) {
      parenthesesCombinations.push(
        ...generateParentheses(
          currentString + ')',
          openCount,
          closeCount + 1,
          maxPairs
        )
      );
    }

    return parenthesesCombinations;
  }

  function checkArrangementValidity(arrangement) {
    const stack = [];
    const matchingParentheses = {
      ')': '(',
      ']': '[',
      '}': '{',
    };

    for (let i = 0; i < arrangement.length; i++) {
      const char = arrangement[i];

      if (char === '(' || char === '[' || char === '{') {
        stack.push(char);
      } else if (char === ')' || char === ']' || char === '}') {
        if (stack.length === 0 || stack.pop() !== matchingParentheses[char]) {
          return false;
        }
      }
    }

    //Stack should be empty if all parentheses are valid
    return stack.length === 0;
  }

  // Get all possible combinations of parentheses
  const allParenthesesCombinations = generateParentheses('', 0, 0, stringLength / 2);

  // Check each combination for validity
  for (let i = 0; i < allParenthesesCombinations.length; i++) {
    const arrangement = allParenthesesCombinations[i];

    // Test each possible combination of parentheses
    if (checkArrangementValidity(arrangement)) {
      return true;
    }
  }

  return false;
}

