class Solution {
    public boolean isValid(String inputString) {
        int stringLength = inputString.length();

        // Strings of odd length cannot be valid
        if (stringLength % 2 != 0) {
            return false;
        }

        return generateAndTest(inputString.toCharArray(), 0);
    }

    private boolean generateAndTest(char[] charArray, int index) {
        if (index == charArray.length) {
            return isValidArrangement(charArray);
        }

        // If we encounter a parenthesis
        if (charArray[index] == '(' || charArray[index] == ')' ||
            charArray[index] == '{' || charArray[index] == '}' ||
            charArray[index] == '[' || charArray[index] == ']') {

            return generateAndTest(charArray, index + 1);
        }

        return false;
    }

    private boolean isValidArrangement(char[] charArray) {
        java.util.Stack<Character> stack = new java.util.Stack<>();

        // Check each char in the string
        for (char character : charArray) {
            if (character == '(') {
                stack.push(')');
            } else if (character == '{') {
                stack.push('}');
            } else if (character == '[') {
                stack.push(']');
            } 
            // Closing parenthesis without a match
            else if (character == ')' || character == '}' || character == ']') {
                if (stack.isEmpty() || stack.pop() != character) {
                    return false;
                }
            }
        }

        // The string is valid only if the stack is empty
        return stack.isEmpty();
    }
}

