    private bool GenerateAndTest(char[] currentArrangement, int currentIndex)
    {
        if (currentIndex == currentArrangement.Length)
        {
            return IsArrangementValid(currentArrangement);
        }

        // Explore every possibility with this parenthesis
        if (currentArrangement[currentIndex] == '(' ||
            currentArrangement[currentIndex] == '{' ||
            currentArrangement[currentIndex] == '[')
        {
            return GenerateAndTest(currentArrangement, currentIndex + 1);
        }
        else
        {
            return GenerateAndTest(currentArrangement, currentIndex + 1);
        }
    }

    private bool IsArrangementValid(char[] arrangementToCheck)
    {
        Stack<char> parenthesisStack = new Stack<char>();

        foreach (char character in arrangementToCheck)
        {
            if (character == '(' || character == '{' || character == '[')
            {
                parenthesisStack.Push(character);
            }
            // Must check to see if the stack is empty before popping
            else if (character == ')' || character == '}' || character == ']')
            {
                if (parenthesisStack.Count == 0)
                {
                    return false;
                }

                char topElement = parenthesisStack.Pop();

                // Validate it is matching
                if ((character == ')' && topElement != '(') ||
                    (character == '}' && topElement != '{') ||
                    (character == ']' && topElement != '['))
                {
                    return false;
                }
            }
        }

        // If any parentheses are left, there was no match
        return parenthesisStack.Count == 0;
    }
