    let parentheses_string: Vec<char> = s.chars().collect();
    let parentheses_count = parentheses_string.len();

    // If odd number, cannot be valid
    if parentheses_count % 2 != 0 {
        return false;
    }

    fn generate_arrangements(parentheses_string: &Vec<char>) -> Vec<Vec<char>> {
        if parentheses_string.is_empty() {
            return vec![vec![]];
        }

        let mut arrangements: Vec<Vec<char>> = Vec::new();
        for i in 0..parentheses_string.len() {
            let current_parenthesis = parentheses_string[i];
            let mut remaining_parentheses = parentheses_string.clone();
            remaining_parentheses.remove(i);

            for arrangement in generate_arrangements(&remaining_parentheses) {
                let mut new_arrangement = vec![current_parenthesis];
                new_arrangement.extend(arrangement);
                arrangements.push(new_arrangement);
            }
        }
        arrangements
    }

    let all_arrangements = generate_arrangements(&parentheses_string);

    for arrangement in all_arrangements {
        let mut stack: Vec<char> = Vec::new();
        let mut is_valid = true;

        // Validate each arrangement.
        for &parenthesis in &arrangement {
            match parenthesis {
                '(' | '{' | '[' => stack.push(parenthesis),
                ')' => {
                    if stack.pop() != Some('(') {
                        is_valid = false;
                        break;
                    }
                }
                '}' => {
                    if stack.pop() != Some('{') {
                        is_valid = false;
                        break;
