    }

    val parenthesesCharacters = charArrayOf('(', ')', '{', '}', '[', ']')

    fun generateParenthesesCombinations(length: Int, currentCombination: String = ""): List<String> {
        if (length == 0) {
            return listOf(currentCombination)
