    //We iterate through each combination
    for (possibleCombination in allCombinations) {
        if (isValidCombination(possibleCombination)) {
            return true
        }
    }

    return false
}

fun isValidCombination(combination: String): Boolean {
    val stack = mutableListOf<Char>()

    //Use stack for checking
    for (character in combination) {
        when (character) {
            '(' -> stack.add(character)
            '{' -> stack.add(character)
            '[' -> stack.add(character)
            ')' -> {
                if (stack.isEmpty() || stack.last() != '(') {
                    return false
                }
                stack.removeAt(stack.size - 1)
            }
            '}' -> {
                if (stack.isEmpty() || stack.last() != '{') {
                    return false
                }
                stack.removeAt(stack.size - 1)
            }
            ']' -> {
                if (stack.isEmpty() || stack.last() != '[') {
                    return false
                }
                stack.removeAt(stack.size - 1)
            }
        }
    }

    // If stack is empty it is valid
