fn is_valid(input_string: String) -> bool {
    let mut expected_closing_characters: VecDeque<char> = VecDeque::new();

    for character in input_string.chars() {
        match character {
            '(' => {
                expected_closing_characters.push_front(')');
            },

            '[' => {
                expected_closing_characters.push_front(']');
            },

            '{' => {
                expected_closing_characters.push_front('}');
            },

            ')' | ']' | '}' => {
                // Need to handle premature closing
                if expected_closing_characters.is_empty() {
                    return false;
