fun isValid(inputString: String): Boolean {
    val expectedParentheses = ArrayDeque<Char>()

    for (character in inputString) {
      if (character == '(' || character == '{' || character == '[') {
        // Opening parenthesis, add to stack
        expectedParentheses.addLast(character)

      } else if (character == ')' || character == '}' || character == ']') {
        // Closing parenthesis.
        if (expectedParentheses.isEmpty()) {
          // Nothing to match with.
          return false
        }

        val lastOpened = expectedParentheses.removeLast()

        //Check if parenthesis match.
        if ((character == ')' && lastOpened != '(') ||
            (character == '}' && lastOpened != '{') ||
            (character == ']' && lastOpened != '[')) {
          return false
        }
      }
    }

    // Stack should be empty if all parentheses matched.
    return expectedParentheses.isEmpty()
  }
}

