struct Stack<Element> {
    private var storage: [Element] = []

    mutating func push(_ element: Element) {
        storage.append(element)
    }

    mutating func pop() -> Element? {
        return storage.popLast()
    }

    func peek() -> Element? {
        return storage.last
    }

    var isEmpty: Bool {
        return storage.isEmpty
    }
}

func isValid(stringToCheck: String) -> Bool {
    var parenthesisStack = Stack<Character>()

    for character in stringToCheck {
        switch character {
        case '(', '{', '[':
            // Push opening parenthesis onto the stack.
            parenthesisStack.push(character)

        case ')':
            // Check if the closing parenthesis matches the last opened one.
            if parenthesisStack.pop() != '(' {
                return false
            }

        case '}':
            if parenthesisStack.pop() != '{' {
                return false
            }

        case ']':
            if parenthesisStack.pop() != '[' {
                return false
            }

        default:
            break
        }
    }

    // String is valid only if we closed all opened parentheses.
    return parenthesisStack.isEmpty
}
